            var uploadsPath = Path.Combine(_env.ContentRootPath, "uploads");
            Directory.CreateDirectory(uploadsPath);

            _uploadsProvider = new PhysicalFileProvider(uploadsPath);

            _contentTypeProvider.Mappings.TryAdd(".pdf", "application/pdf");
            _contentTypeProvider.Mappings.TryAdd(".doc", "application/msword");
            _contentTypeProvider.Mappings.TryAdd(".docx", "application/vnd.openxmlformats-officedocument.wordprocessingml.document");
            _contentTypeProvider.Mappings.TryAdd(".xls", "application/vnd.ms-excel");
            _contentTypeProvider.Mappings.TryAdd(".xlsx", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
            _contentTypeProvider.Mappings.TryAdd(".ppt", "application/vnd.ms-powerpoint");
            _contentTypeProvider.Mappings.TryAdd(".pptx", "application/vnd.openxmlformats-officedocument.presentationml.presentation");
            _contentTypeProvider.Mappings.TryAdd(".csv", "text/csv");
            _contentTypeProvider.Mappings.TryAdd(".txt", "text/plain");
            _contentTypeProvider.Mappings.TryAdd(".rtf", "application/rtf");
        }

        [HttpGet("{filename}")]
        public IActionResult Get([FromRoute] string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
